#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B, C;
        scanf("%lld %lld %lld", &A, &B, &C);
        long long chef = A * C;
        long long chefina = B * C;
        long long ans = chef > chefina ? chef : chefina;
        printf("%lld\n", ans);
    }
    return 0;
}

